import argparse
import json
import os
from pathlib import Path

import numpy as np
import soundfile as sf
import torch
import torchaudio
from torch.utils.data import DataLoader, Dataset, Sampler
from transformers import AutoFeatureExtractor

from model import build_model


def find_test_root(data_path: str) -> Path:
    seeds = []
    for p in [data_path, os.environ.get('RAB_DATA_DIR'), '/data', '/rab_data', '/workspace']:
        if p:
            seeds.append(Path(p))

    seen = set()
    queue = []
    for p in seeds:
        try:
            rp = p.resolve()
        except Exception:
            rp = p
        s = str(rp)
        if s not in seen and rp.exists():
            seen.add(s)
            queue.append(rp)

    candidates = []
    for root in queue:
        candidates.append(root)
        if root.is_dir():
            try:
                for child in root.rglob('*'):
                    if child.is_dir():
                        candidates.append(child)
            except Exception:
                pass

    uniq = []
    seen = set()
    for p in candidates:
        try:
            rp = p.resolve()
        except Exception:
            rp = p
        s = str(rp)
        if s not in seen:
            seen.add(s)
            uniq.append(rp)

    for cand in uniq:
        if (cand / 'test.txt').is_file() and (cand / 'flac').is_dir():
            return cand

    raise FileNotFoundError(f'Could not locate test root under {data_path}')


def load_audio(path: Path) -> np.ndarray:
    try:
        wav, sr = sf.read(str(path), always_2d=False)
        if wav.ndim > 1:
            wav = wav.mean(axis=1)
        wav = wav.astype(np.float32)
        if sr != 16000:
            raise ValueError(f'Expected 16k audio, got {sr} for {path}')
        return wav
    except Exception:
        wav, sr = torchaudio.load(str(path))
        if wav.dim() == 2 and wav.size(0) > 1:
            wav = wav.mean(dim=0, keepdim=True)
        wav = wav.squeeze(0).float().cpu().numpy()
        if sr != 16000:
            raise ValueError(f'Expected 16k audio, got {sr} for {path}')
        return wav.astype(np.float32)


def get_num_frames(path: Path) -> int:
    try:
        return int(sf.info(str(path)).frames)
    except Exception:
        wav, _ = torchaudio.load(str(path))
        return int(wav.shape[-1])


class TestDataset(Dataset):
    def __init__(self, data_path: str):
        self.root = find_test_root(data_path)
        self.flac_dir = self.root / 'flac'
        with open(self.root / 'test.txt') as f:
            self.utt_ids = [line.strip() for line in f if line.strip()]
        self.paths = [self.flac_dir / f'{utt}.flac' for utt in self.utt_ids]
        self.lengths = [get_num_frames(p) for p in self.paths]

    def __len__(self):
        return len(self.utt_ids)

    def __getitem__(self, idx):
        wav = load_audio(self.paths[idx])
        return {
            'input_values': wav,
            'index': idx,
            'length': len(wav),
        }


class SortedBatchSampler(Sampler):
    def __init__(self, lengths, batch_size: int):
        self.batch_size = batch_size
        self.indices = np.argsort(np.asarray(lengths)).tolist()

    def __iter__(self):
        batch = []
        for idx in self.indices:
            batch.append(idx)
            if len(batch) == self.batch_size:
                yield batch
                batch = []
        if batch:
            yield batch

    def __len__(self):
        return (len(self.indices) + self.batch_size - 1) // self.batch_size


class Collator:
    def __init__(self, feature_extractor):
        self.feature_extractor = feature_extractor

    def __call__(self, batch):
        wavs = [b['input_values'] for b in batch]
        enc = self.feature_extractor(
            wavs,
            sampling_rate=16000,
            return_tensors='pt',
            padding=True,
            return_attention_mask=True,
        )
        input_values = enc['input_values']
        attention_mask = enc['attention_mask'] if 'attention_mask' in enc else torch.ones_like(input_values, dtype=torch.long)
        indices = torch.tensor([b['index'] for b in batch], dtype=torch.long)
        return {
            'input_values': input_values,
            'attention_mask': attention_mask,
            'index': indices,
        }


def load_feature_extractor(ckpt: dict):
    local_dir = ckpt.get('feature_extractor_local_dir')
    if local_dir and Path(local_dir).exists():
        feat = AutoFeatureExtractor.from_pretrained(local_dir, local_files_only=True)
    elif Path('artifacts/feature_extractor').exists():
        feat = AutoFeatureExtractor.from_pretrained('artifacts/feature_extractor', local_files_only=True)
    else:
        feat = AutoFeatureExtractor.from_pretrained(ckpt['feature_extractor_name'], local_files_only=True)
    if hasattr(feat, 'return_attention_mask'):
        feat.return_attention_mask = True
    return feat


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)
    parser.add_argument('--output', type=str, required=True)
    parser.add_argument('--batch_size', type=int, default=64)
    args = parser.parse_args()

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    ckpt = torch.load(args.checkpoint, map_location='cpu')

    model = build_model(ckpt['model_config'])
    model.load_state_dict(ckpt['model_state'])
    model.to(device)
    model.eval()

    feature_extractor = load_feature_extractor(ckpt)
    dataset = TestDataset(args.data_path)
    sampler = SortedBatchSampler(dataset.lengths, batch_size=args.batch_size)
    loader = DataLoader(
        dataset,
        batch_sampler=sampler,
        num_workers=0,
        pin_memory=(device.type == 'cuda'),
        collate_fn=Collator(feature_extractor),
    )

    preds = np.zeros(len(dataset), dtype=np.float32)
    amp_enabled = device.type == 'cuda'
    with torch.no_grad():
        for batch in loader:
            x = batch['input_values'].to(device, non_blocking=True)
            m = batch['attention_mask'].to(device, non_blocking=True)
            with torch.amp.autocast('cuda', dtype=torch.bfloat16, enabled=amp_enabled):
                logits = model(x, m)
            logits = logits.float().cpu().numpy()
            idx = batch['index'].cpu().numpy()
            preds[idx] = logits

    out_path = Path(args.output)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    with open(out_path, 'w') as f:
        json.dump({'predictions': preds.tolist()}, f)


if __name__ == '__main__':
    main()
